// src/pages/RegisterPage.js 
import { useState } from 'react'; 
import Nav from '../components/Nav';
import BackToTop from '../components/BackToTop';  
function RegisterPage() { 
  const [formData, setFormData] = useState({ 
    name: '', 
    username: '', 
    birth: '', 
    password: '', 
    confirmPassword: '', 
    gender: '', 
    accountType: '', 
    agree: false, 
  }); 
  const [errors, setErrors] = useState({}); 
  const [submitted, setSubmitted] = useState(false); 
  
  const handleChange = (e) => { 
    const { name, value, type, checked } = e.target; 
    setFormData({ 
      ...formData, 
      [name]: type === 'checkbox' ? checked : value, 
    }); 
  }; 
  
  const validateForm = () => { 
    let isValid = true; 
    const newErrors = {}; 
    
    if (formData.name.trim() === '') { 
      newErrors.name = 'Name is required'; 
      isValid = false; 
    } 
    
    if (formData.username.length < 4) { 
      newErrors.username = 'Username must be at least 4 characters'; 
      isValid = false; 
    } 
    
    if (formData.birth === '') { 
      newErrors.birth = 'Birth date is required'; 
      isValid = false; 
    } else { 
      const birthDate = new Date(formData.birth); 
      const today = new Date(); 
      let age = today.getFullYear() - birthDate.getFullYear(); 
      const m = today.getMonth() - birthDate.getMonth(); 
      if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) { 
        age--; 
      } 
      if (age < 18) { 
        newErrors.birth = 'You must be at least 18 years old'; 
        isValid = false; 
      } 
    } 
    
    if (formData.password.length < 8) { 
      newErrors.password = 'Password must be at least 8 characters'; 
      isValid = false; 
    } 
    
    if (formData.password !== formData.confirmPassword) { 
      newErrors.confirmPassword = 'Passwords do not match'; 
      isValid = false; 
    } 
    
    if (!formData.gender) { 
      newErrors.gender = 'Please select a gender'; 
      isValid = false; 
    } 
    
    if (formData.accountType === '') { 
      newErrors.accountType = 'Select an account type'; 
      isValid = false; 
    } 
    
    setErrors(newErrors); 
    return isValid; 
  }; 
  
  const handleSubmit = (e) => { 
    e.preventDefault(); 
    if (validateForm()) { 
      console.log('Registration submitted:', formData); 
      setSubmitted(true); 
    } 
  }; 
  
  return ( 
    <> 
      <Nav /> 
      <main> 
        <section className="register-section"> 
          <h2 className="register-title">Join the BTS Community</h2> 
          <p className="register-subtitle">This form is for demonstration purposes only.</p> 
          
          {submitted ? ( 
            <p>Thank you for registering! Welcome to our blog.</p> 
          ) : ( 
            <form id="registerForm" className="register-form" onSubmit={handleSubmit}> 
              <div> 
                <label htmlFor="name">Name:</label> 
                <input type="text" id="name" name="name" value={formData.name} onChange={handleChange} /> 
                <span className="error">{errors.name}</span> 
              </div> 
              
              <div> 
                <label htmlFor="username">Preferred Username:</label> 
                <input type="text" id="username" name="username" value={formData.username} onChange={handleChange} /> 
                <span className="error">{errors.username}</span> 
              </div> 
              
              <div> 
                <label htmlFor="birth">Date of Birth:</label> 
                <input type="date" id="birth" name="birth" value={formData.birth} onChange={handleChange} /> 
                <span className="error">{errors.birth}</span> 
              </div> 
              
              <div> 
                <label htmlFor="password">Password:</label> 
                <input type="password" id="password" name="password" value={formData.password} onChange={handleChange} /> 
                <span className="error">{errors.password}</span> 
              </div> 
              
              <div> 
                <label htmlFor="confirmPassword">Confirm Password:</label> 
                <input type="password" id="confirmPassword" name="confirmPassword" value={formData.confirmPassword} onChange={handleChange} /> 
                <span className="error">{errors.confirmPassword}</span> 
              </div> 
              
              <div className="radio-group"> 
                <label>Gender:</label> 
                <input type="radio" name="gender" value="male" checked={formData.gender === 'male'} onChange={handleChange} /> Male 
                <input type="radio" name="gender" value="female" checked={formData.gender === 'female'} onChange={handleChange} /> Female 
                <input type="radio" name="gender" value="other" checked={formData.gender === 'other'} onChange={handleChange} /> Other 
                <span className="error">{errors.gender}</span> 
              </div> 
              
              <div> 
                <label htmlFor="accountType">Account Type:</label> 
                <select id="accountType" name="accountType" value={formData.accountType} onChange={handleChange}> 
                  <option value="">Select</option> 
                  <option value="basic">Basic</option> 
                  <option value="premium">Premium</option> 
                  <option value="admin">Admin</option> 
                </select> 
                <span className="error">{errors.accountType}</span> 
              </div> 
              
              <label> 
                <input type="checkbox" name="agree" checked={formData.agree} onChange={handleChange} required /> I agree to the terms and conditions 
              </label> 
              
              <button type="submit">Register</button> 
            </form> 
          )} 
        </section> 
      </main> 
      
      <footer className="site-footer"> 
        <p>Contact: stephaniepepito01@gmail.com</p> 
        <p>&copy; 2026 BTS: The Music That Shaped My Journey</p> 
      </footer> 
    </> 
  ); 
} 
export default RegisterPage;
